+import type { DurationObservation } from './duration-smoothing'
+import { mkdir, readFile, writeFile } from 'node:fs/promises'
+import { dirname, resolve } from 'pathe'
+
+export type DurationHistory = Record<string, DurationObservation[]>
+
+function observations(value: unknown): DurationObservation[] | null {
+  if (typeof value === 'number' && Number.isFinite(value)) return [{ duration: value, recordedAt: 0 }]
+  const entries = typeof value === 'object' && value !== null && 'observations' in value
+    ? (value as { observations: unknown }).observations
+    : [value]
+  if (!Array.isArray(entries)) return null
+  const result = entries.filter((entry): entry is DurationObservation => typeof entry === 'object' && entry !== null && Number.isFinite((entry as DurationObservation).duration) && Number.isFinite((entry as DurationObservation).recordedAt))
+  return result.length === entries.length ? result : null
+}
+
+export async function readDurationHistory(root: string, path: string, ttl: number): Promise<DurationHistory | null> {
+  try {
+    const parsed: unknown = JSON.parse(await readFile(resolve(root, path), 'utf8'))
+    if (typeof parsed !== 'object' || parsed === null || Array.isArray(parsed)) return null
+    const cutoff = Date.now() - ttl
+    const history: DurationHistory = {}
+    for (const [file, value] of Object.entries(parsed)) {
+      const entries = observations(value)
+      if (!entries) return null
+      history[file] = ttl > 0 ? entries.filter(entry => entry.recordedAt === 0 || entry.recordedAt >= cutoff) : entries
+    }
+    return history
+  }
+  catch {
+    return null
+  }
+}
+
+export async function writeDurationHistory(root: string, path: string, history: DurationHistory, maxRuns: number): Promise<void> {
+  const output: Record<string, unknown> = {}
+  for (const [file, entries] of Object.entries(history)) {
+    const recent = [...entries].sort((a, b) => b.recordedAt - a.recordedAt).slice(0, maxRuns)
+    output[file] = maxRuns === 1 ? recent[0] : { observations: recent }
+  }
+  const file = resolve(root, path)
+  await mkdir(dirname(file), { recursive: true })
+  await writeFile(file, `${JSON.stringify(output, null, 2)}\
`)
