+export function smoothDurations(observations: DurationObservation[], method: 'latest' | 'average' | 'p95' | 'median'): number {
+  if (!observations.length) return 0
+  if (method === 'latest') return observations.reduce((latest, observation) => observation.recordedAt > latest.recordedAt ? observation : latest).duration
+  const durations = observations.map(observation => observation.duration).sort((a, b) => a - b)
