+function observations(value: unknown): DurationObservation[] | null {
+  if (typeof value === 'number' && Number.isFinite(value)) return [{ duration: value, recordedAt: 0 }]
+  const entries = typeof value === 'object' && value !== null && 'observations' in value
+    ? (value as { observations: unknown }).observations
